```class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.size();
        vector<int> prefixSum(n + 1, 0);

        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = prefixSum[i] + (customers[i] == 'Y' ? -1 : 1);
        }

        int minPenalty = INT_MAX;
        int bestTime = 0;

        for (int i = 0; i <= n; i++) {
            int penalty = prefixSum[i] + (i < n ? prefixSum[n] - prefixSum[i] : 0);
            if (penalty < minPenalty) {
                minPenalty = penalty;
                bestTime = i;
            }
        }

        return bestTime;
    }
};
